    base = [[(i + j) % 2 for j in range(n)] for i in range(n)]
    if rng.random() < 0.5:
        base = [[1 - v for v in row] for row in base]
    for _ in range(rng.randint(0, 40)):
        a, b = rng.randrange(n), rng.randrange(n)
        base[a], base[b] = base[b], base[a]
    for _ in range(rng.randint(0, 40)):
        a, b = rng.randrange(n), rng.randrange(n)
        for row in base:
            row[a], row[b] = row[b], row[a]
