var movesToChessboard = function(board) {
    const n = board.length;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if ((board[0][0] ^ board[i][0] ^ board[0][j] ^ board[i][j]) !== 0) return -1;
        }
    }
    let rowSum = 0, colSum = 0;
    for (let k = 0; k < n; k++) { rowSum += board[0][k]; colSum += board[k][0]; }
    if (!(rowSum >= Math.floor(n / 2) && rowSum <= Math.floor((n + 1) / 2))) return -1;
    if (!(colSum >= Math.floor(n / 2) && colSum <= Math.floor((n + 1) / 2))) return -1;
    let rowSwap = 0, colSwap = 0;
    for (let i = 0; i < n; i++) if (board[i][0] === i % 2) rowSwap++;
    for (let j = 0; j < n; j++) if (board[0][j] === j % 2) colSwap++;
    if (n % 2) {
        if (rowSwap % 2) rowSwap = n - rowSwap;
        if (colSwap % 2) colSwap = n - colSwap;
    } else {
        rowSwap = Math.min(rowSwap, n - rowSwap);
        colSwap = Math.min(colSwap, n - colSwap);
    }
    return (rowSwap + colSwap) / 2;
};
